        self.seq = []
        for i in range(0, len(encoding), 2):
            self.seq.extend([encoding[i + 1]] * encoding[i])
        self.pos = 0
    def next(self, n):
        self.pos += n
        if self.pos <= len(self.seq):
            return self.seq[self.pos - 1]
        return -1

