class RLEIterator:
    def __init__(self, encoding):
        self.enc = encoding
        self.idx = 0
        self.remain = encoding[0] if encoding else 0
    def next(self, n):
        last = -1
        while n > 0 and self.idx < len(self.enc):
            if self.remain >= n:
                self.remain -= n
                last = self.enc[self.idx + 1]
                n = 0
            else:
                n -= self.remain
                self.idx += 2
                if self.idx < len(self.enc):
                    self.remain = self.enc[self.idx]
                else:
                    return -1
        if n > 0:
            return -1
        return last

